                  placeholder="Ask a question..."
                  className="w-full bg-gray-100 border-none rounded-xl py-2.5 px-4 focus:ring-2 focus:ring-aucdt-maroon/20 focus:bg-white transition-all resize-none max-h-24 min-h-[44px] text-sm"
