const App: React.FC = () => {
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [currentView, setCurrentView] = useState<'home' | 'admin'>('home');

  // Handle hash-based routing for simple state persistence
  useEffect(() => {
    const handleHashChange = () => {
      const hash = window.location.hash;
      if (hash === '#admin') {
        setCurrentView('admin');
      } else {
        setCurrentView('home');
      }
    };

    // Check initial hash
    handleHashChange();

    window.addEventListener('hashchange', handleHashChange);
    return () => window.removeEventListener('hashchange', handleHashChange);
  }, []);

  const navigateTo = (view: 'home' | 'admin') => {
    if (view === 'admin') {
      window.location.hash = 'admin';
    } else {
      window.location.hash = '';
      // Also remove the hash character for cleaner URL if supported
      if (window.history.pushState) {
        window.history.pushState("", document.title, window.location.pathname + window.location.search);
      }
    }
    // State update happens via the hashchange listener
  };

  const toggleChat = () => setIsChatOpen(prev => !prev);
  const openChat = () => setIsChatOpen(true);
  const closeChat = () => setIsChatOpen(false);

  // Skip to content for accessibility
  const skipToContent = (e: React.MouseEvent<HTMLAnchorElement>) => {
    e.preventDefault();
    const mainContent = document.getElementById('main-content');
    if (mainContent) {
      mainContent.focus();
      mainContent.scrollIntoView();
    }
  };

  return (
    <ThemeProvider>
      <div className="min-h-screen bg-white dark:bg-gray-900 transition-colors duration-300 flex flex-col relative font-sans text-gray-900 dark:text-gray-100">

        {/* Accessibility Skip Link */}
        <a 
          href="#main-content"
          onClick={skipToContent}
          className="sr-only focus:not-sr-only focus:absolute focus:top-4 focus:left-4 z-[100] bg-aucdt-maroon text-white px-4 py-2 rounded font-bold shadow-lg"
        >
          Skip to main content
        </a>

        {currentView === 'admin' ? (
          <Admin onBack={() => navigateTo('home')} />
        ) : (
          <>
            <Header onChatToggle={toggleChat} />
            <main id="main-content" className="flex-grow focus:outline-none" tabIndex={-1}>
              <HeroSlider />
              <CTASection />
              <Programs />
              <Scholarship />
              <NewsFeed />
              <SecondaryCTA />
              <Accreditation />
            </main>
            <Footer onAdminClick={() => navigateTo('admin')} />
            <AIChatAgent 
              isOpen={isChatOpen} 
              onClose={closeChat} 
              onOpen={openChat}
            />
          </>
        )}
      </div>
    </ThemeProvider>
  );
