import React, { useState, useRef, useEffect } from 'react';
import { Play, CheckCircle, XCircle, Terminal, Activity, ArrowLeft, Shield } from 'lucide-react';
import { TEST_SUITE, TestResult } from '../lib/testRunner';

interface PuppeteerSelfTestProps {
  onBack: () => void;
}

const PuppeteerSelfTest: React.FC<PuppeteerSelfTestProps> = ({ onBack }) => {
  const [results, setResults] = useState<TestResult[]>(
    TEST_SUITE.map(t => ({ name: t.name, status: 'pending', logs: [] }))
  );
  const [isRunning, setIsRunning] = useState(false);
  const [activeTestIndex, setActiveTestIndex] = useState<number | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);

  const runTests = async () => {
    if (isRunning) return;
    setIsRunning(true);

    // Reset
    setResults(TEST_SUITE.map(t => ({ name: t.name, status: 'pending', logs: [] })));

    for (let i = 0; i < TEST_SUITE.length; i++) {
      setActiveTestIndex(i);
      const test = TEST_SUITE[i];
      const startTime = Date.now();

      // Update status to running
      setResults(prev => {
        const next = [...prev];
        next[i] = { ...next[i], status: 'running' };
        return next;
      });

      try {
        await test.action((msg) => {
          setResults(prev => {
            const next = [...prev];
            next[i].logs.push(`[${new Date().toLocaleTimeString()}] ${msg}`);
            return next;
          });
          // Auto scroll
          if (scrollRef.current) {
            scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
          }
        });

        // Pass
        setResults(prev => {
          const next = [...prev];
          next[i] = { 
            ...next[i], 
            status: 'passed', 
            duration: Date.now() - startTime,
            logs: [...next[i].logs, `[SUCCESS] Test completed in ${Date.now() - startTime}ms`]
          };
          return next;
        });

      } catch (e: any) {
        // Fail
        setResults(prev => {
          const next = [...prev];
          next[i] = { 
            ...next[i], 
            status: 'failed', 
            error: e.message,
            duration: Date.now() - startTime,
            logs: [...next[i].logs, `[ERROR] ${e.message}`]
          };
          return next;
        });
      }

      // Brief pause between tests for visual clarity
      await new Promise(r => setTimeout(r, 800));
    }

    setIsRunning(false);
    setActiveTestIndex(null);
  };

  return (
    <div className="min-h-screen bg-gray-900 text-gray-200 font-mono p-4 md:p-8">
      <div className="max-w-6xl mx-auto">
        {/* Header */}
        <header className="flex justify-between items-center mb-8 border-b border-gray-700 pb-6">
          <div className="flex items-center space-x-4">
            <div className="bg-blue-600 p-2 rounded-lg">
              <Terminal size={24} className="text-white" />
            </div>
            <div>
              <h1 className="text-2xl font-bold text-white tracking-tight">Puppeteer Self-Test Suite</h1>
              <p className="text-gray-400 text-sm">Automated Browser Integration Testing Framework v1.0</p>
            </div>
          </div>
          <button 
            onClick={onBack}
            className="flex items-center px-4 py-2 bg-gray-800 hover:bg-gray-700 rounded text-sm transition-colors"
          >
            <ArrowLeft size={16} className="mr-2" /> Exit Suite
          </button>
        </header>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* Sidebar / Control Panel */}
          <div className="lg:col-span-1 space-y-6">
            <div className="bg-gray-800 rounded-xl p-6 border border-gray-700 shadow-xl">
              <h2 className="text-lg font-semibold text-white mb-4 flex items-center">
                <Activity size={18} className="mr-2 text-green-400" />
                Control Panel
              </h2>
              <p className="text-gray-400 text-sm mb-6">
                Execute the critical user journey test suite. This process will interact with the live application DOM to verify functionality.
              </p>

              <button
                onClick={runTests}
                disabled={isRunning}
                className={`w-full py-3 px-4 rounded-lg font-bold flex items-center justify-center transition-all ${
                  isRunning 
                    ? 'bg-gray-700 text-gray-400 cursor-not-allowed' 
                    : 'bg-green-600 hover:bg-green-500 text-white shadow-lg hover:shadow-green-500/20'
                }`}
              >
                {isRunning ? (
                  <>
                    <Activity size={18} className="mr-2 animate-spin" /> Running Suite...
                  </>
                ) : (
                  <>
                    <Play size={18} className="mr-2" /> Run Diagnostics
                  </>
                )}
              </button>
            </div>

            {/* Test List Status */}
            <div className="bg-gray-800 rounded-xl overflow-hidden border border-gray-700">
              <div className="px-6 py-4 bg-gray-800/50 border-b border-gray-700">
                <h3 className="text-sm font-semibold uppercase tracking-wider text-gray-400">Test Cases</h3>
              </div>
              <div className="divide-y divide-gray-700">
                {results.map((test, idx) => (
                  <div 
                    key={idx} 
                    className={`px-6 py-4 flex items-center justify-between transition-colors ${
                      activeTestIndex === idx ? 'bg-blue-900/20' : ''
                    }`}
                  >
                    <div className="flex items-center space-x-3">
                      {test.status === 'pending' && <div className="w-5 h-5 rounded-full border-2 border-gray-600" />}
                      {test.status === 'running' && <LoaderIcon />}
                      {test.status === 'passed' && <CheckCircle size={20} className="text-green-500" />}
                      {test.status === 'failed' && <XCircle size={20} className="text-red-500" />}
                      <span className={`text-sm font-medium ${
                        test.status === 'pending' ? 'text-gray-500' :
                        test.status === 'running' ? 'text-blue-400' :
                        'text-gray-200'
                      }`}>
                        {test.name}
                      </span>
                    </div>
                    {test.duration && (
                      <span className="text-xs text-gray-500 font-mono">{test.duration}ms</span>
                    )}
                  </div>
                ))}
              </div>
            </div>
          </div>

          {/* Terminal / Output */}
          <div className="lg:col-span-2">
            <div className="bg-black/80 rounded-xl border border-gray-700 shadow-2xl h-[600px] flex flex-col backdrop-blur-sm">
              <div className="px-4 py-2 bg-gray-800/80 rounded-t-xl border-b border-gray-700 flex space-x-2 items-center">
                <div className="w-3 h-3 rounded-full bg-red-500"></div>
                <div className="w-3 h-3 rounded-full bg-yellow-500"></div>
                <div className="w-3 h-3 rounded-full bg-green-500"></div>
                <span className="ml-4 text-xs text-gray-400 font-mono">puppeteer-runner --verbose</span>
              </div>

              <div 
                ref={scrollRef}
                className="flex-1 p-6 overflow-y-auto font-mono text-sm space-y-2"
              >
                <div className="text-gray-500 mb-4">
                  $ initializing test environment...<br/>
                  $ loading test_suite_v1.0.js...<br/>
                  $ ready.
                </div>

                {results.flatMap((t, tIdx) => 
                  t.logs.map((log, lIdx) => (
                    <div key={`${tIdx}-${lIdx}`} className="flex">
                      <span className="text-blue-500 mr-2">➜</span>
                      <span className={`${
                        log.includes('[ERROR]') ? 'text-red-400' :
                        log.includes('[SUCCESS]') ? 'text-green-400' :
                        'text-gray-300'
                      }`}>
                        {log}
                      </span>
                    </div>
                  ))
                )}

                {activeTestIndex === null && isRunning === false && results.some(r => r.status !== 'pending') && (
                   <div className="mt-8 pt-4 border-t border-gray-800">
                     <div className="text-white font-bold">
                       SUMMARY: 
                       <span className="text-green-400 ml-2">{results.filter(r => r.status === 'passed').length} Passed</span>
                       <span className="text-red-400 ml-4">{results.filter(r => r.status === 'failed').length} Failed</span>
                     </div>
                     <div className="text-gray-500 mt-2">$ awaiting input...</div>
                   </div>
                )}
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

const LoaderIcon = () => (
  <svg className="animate-spin h-5 w-5 text-blue-500" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
  </svg>
);

export default PuppeteerSelfTest;

import React, { useState, useEffect } from 'react';
import Header from './components/Header';
import HeroSlider from './components/HeroSlider';
import CTASection from './components/CTASection';
import Programs from './components/Programs';
import Scholarship from './components/Scholarship';
import SecondaryCTA from './components/SecondaryCTA';
import Accreditation from './components/Accreditation';
import Footer from './components/Footer';
import AIChatAgent from './components/AIChatAgent';
import NewsFeed from './components/NewsFeed';
import Admin from './components/Admin';
import PuppeteerSelfTest from './components/PuppeteerSelfTest';
import { ThemeProvider } from './context/ThemeContext';

const App: React.FC = () => {
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [currentView, setCurrentView] = useState<'home' | 'admin' | 'test'>('home');

  // Handle hash-based routing for simple state persistence
  useEffect(() => {
    const handleHashChange = () => {
      const hash = window.location.hash;
      if (hash === '#admin') {
        setCurrentView('admin');
      } else if (hash === '#test') {
        setCurrentView('test');
      } else {
        setCurrentView('home');
      }
    };

    // Check initial hash
    handleHashChange();

    window.addEventListener('hashchange', handleHashChange);
    return () => window.removeEventListener('hashchange', handleHashChange);
  }, []);

  const navigateTo = (view: 'home' | 'admin' | 'test') => {
    if (view === 'admin') {
      window.location.hash = 'admin';
    } else if (view === 'test') {
      window.location.hash = 'test';
    } else {
      window.location.hash = '';
      if (window.history.pushState) {
        window.history.pushState("", document.title, window.location.pathname + window.location.search);
      }
    }
  };

  const toggleChat = () => setIsChatOpen(prev => !prev);
  const openChat = () => setIsChatOpen(true);
  const closeChat = () => setIsChatOpen(false);

  const skipToContent = (e: React.MouseEvent<HTMLAnchorElement>) => {
    e.preventDefault();
    const mainContent = document.getElementById('main-content');
    if (mainContent) {
      mainContent.focus();
      mainContent.scrollIntoView();
    }
  };

  return (
    <ThemeProvider>
      <div className="min-h-screen bg-white dark:bg-gray-900 transition-colors duration-300 flex flex-col relative font-sans text-gray-900 dark:text-gray-100">

        <a 
          href="#main-content"
          onClick={skipToContent}
          className="sr-only focus:not-sr-only focus:absolute focus:top-4 focus:left-4 z-[100] bg-aucdt-maroon text-white px-4 py-2 rounded font-bold shadow-lg"
        >
          Skip to main content
        </a>

        {currentView === 'admin' ? (
          <Admin onBack={() => navigateTo('home')} />
        ) : currentView === 'test' ? (
          <PuppeteerSelfTest onBack={() => navigateTo('home')} />
        ) : (
          <>
            <Header onChatToggle={toggleChat} />
            <main id="main-content" className="flex-grow focus:outline-none" tabIndex={-1}>
              <HeroSlider />
              <CTASection />
              <Programs />
              <Scholarship />
              <NewsFeed />
              <SecondaryCTA />
              <Accreditation />
            </main>
            <Footer 
              onAdminClick={() => navigateTo('admin')} 
              onTestClick={() => navigateTo('test')}
            />
            <AIChatAgent 
              isOpen={isChatOpen} 
              onClose={closeChat} 
              onOpen={openChat}
            />
          </>
        )}
      </div>
    </ThemeProvider>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { ChevronLeft, ChevronRight, ArrowRight } from 'lucide-react';
import { HERO_SLIDES } from '../constants';

const HeroSlider: React.FC = () => {
  const [currentSlide, setCurrentSlide] = useState(0);
  const [isPaused, setIsPaused] = useState(false);
  const [progress, setProgress] = useState(0);

  // Settings
  const SLIDE_DURATION = 6000; // ms

  useEffect(() => {
    let animationFrameId: number;
    let lastTime = Date.now();

    const animate = () => {
      if (!isPaused) {
        const now = Date.now();
        const delta = now - lastTime;
        lastTime = now;

        setProgress(prev => {
          const newProgress = prev + (delta / SLIDE_DURATION) * 100;
          if (newProgress >= 100) {
            setCurrentSlide(curr => (curr + 1) % HERO_SLIDES.length);
            return 0;
          }
          return newProgress;
        });
      } else {
        lastTime = Date.now(); // Prevent jump when unpausing
      }
      animationFrameId = requestAnimationFrame(animate);
    };

    animationFrameId = requestAnimationFrame(animate);

    return () => cancelAnimationFrame(animationFrameId);
  }, [isPaused]);

  // Reset progress when slide changes manually
  const goToSlide = (index: number) => {
    setCurrentSlide(index);
    setProgress(0);
  };

  const nextSlide = () => {
    setCurrentSlide((prev) => (prev + 1) % HERO_SLIDES.length);
    setProgress(0);
  };

  const prevSlide = () => {
    setCurrentSlide((prev) => (prev === 0 ? HERO_SLIDES.length - 1 : prev - 1));
    setProgress(0);
  };

  return (
    <section 
      className="relative w-full h-[600px] md:h-[750px] overflow-hidden bg-gray-900 group"
      onMouseEnter={() => setIsPaused(true)}
      onMouseLeave={() => setIsPaused(false)}
      aria-label="University Highlights Carousel"
    >
      {HERO_SLIDES.map((slide, index) => {
        const isActive = index === currentSlide;
        return (
          <div
            key={slide.id}
            className={`absolute inset-0 w-full h-full transition-opacity duration-1000 ease-in-out ${
              isActive ? 'opacity-100 z-10' : 'opacity-0 z-0'
            }`}
            aria-hidden={!isActive}
          >
            {/* Background Image with Parallax-like Ken Burns */}
            <div className="absolute inset-0 overflow-hidden">
               <div 
                className={`w-full h-full bg-cover bg-center transition-transform duration-[10000ms] ease-linear transform origin-center ${
                  isActive ? 'scale-110' : 'scale-100'
                }`}
                style={{ backgroundImage: `url(${slide.image})` }}
              />
            </div>

            {/* Modern Gradient Overlay: Darker at bottom/left for text readability */}
            <div className="absolute inset-0 bg-gradient-to-r from-black/80 via-black/40 to-transparent"></div>
            <div className="absolute inset-0 bg-gradient-to-t from-black/90 via-transparent to-transparent opacity-80"></div>

            {/* Content Container */}
            <div className="absolute inset-0 flex items-center p-6 md:p-12 lg:p-20">
              <div className="max-w-7xl mx-auto w-full grid grid-cols-1 lg:grid-cols-12 gap-8">

                {/* Text Content - Left Aligned */}
                <div className="lg:col-span-8 flex flex-col justify-center text-left">
                  {/* We use a specific key on the inner div to trigger re-animations on slide change */}
                  <div key={`text-${currentSlide}-${index}`} className={`${isActive ? 'block' : 'hidden'}`}>

                    <div className="overflow-hidden mb-4">
                      <h2 className="text-lg md:text-xl font-medium text-aucdt-gold tracking-[0.2em] uppercase animate-fade-in-down">
                        {slide.title}
                      </h2>
                    </div>

                    <div className="overflow-hidden mb-8">
                      <h1 className="text-4xl md:text-6xl lg:text-7xl font-bold text-white leading-[1.1] font-sans animate-fade-in-up animation-delay-200 drop-shadow-lg">
                        {slide.subtitle}
                      </h1>
                    </div>

                    <div className="animate-fade-in-up animation-delay-400">
                      <a 
                        href={slide.ctaLink}
                        className="group/btn inline-flex items-center gap-3 bg-white/10 backdrop-blur-md border border-white/30 text-white px-8 py-4 text-base font-bold rounded-lg hover:bg-aucdt-gold hover:border-aucdt-gold hover:text-aucdt-maroon transition-all duration-300 uppercase tracking-wide shadow-lg"
                      >
                        {slide.ctaText}
                        <ArrowRight size={20} className="transform group-hover/btn:translate-x-1 transition-transform" />
                      </a>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        );
      })}

      {/* Modern Navigation Controls */}

      {/* 1. Side List Navigation (Desktop) */}
      <div className="absolute right-0 top-0 bottom-0 hidden lg:flex flex-col justify-center px-8 z-30 w-1/4 bg-gradient-to-l from-black/60 to-transparent">
        <div className="space-y-6">
          {HERO_SLIDES.map((slide, index) => (
            <button
              key={slide.id}
              onClick={() => goToSlide(index)}
              className={`group flex items-center justify-end w-full text-right transition-all duration-300 outline-none ${
                index === currentSlide ? 'opacity-100' : 'opacity-40 hover:opacity-70'
              }`}
            >
              <span className={`mr-4 text-sm font-medium text-white transition-all duration-300 ${
                 index === currentSlide ? 'translate-x-0' : 'translate-x-2 group-hover:translate-x-0'
              }`}>
                {slide.subtitle.split(' ').slice(0, 3).join(' ')}...
              </span>
              <div className={`h-0.5 transition-all duration-300 ${
                index === currentSlide ? 'w-12 bg-aucdt-gold h-1' : 'w-6 bg-white group-hover:w-8'
              }`} />
            </button>
          ))}
        </div>
      </div>

      {/* 2. Bottom Progress Bar */}
      <div className="absolute bottom-0 left-0 w-full h-1.5 bg-gray-800/50 z-30">
         <div 
           className="h-full bg-aucdt-gold shadow-[0_0_10px_rgba(255,203,5,0.7)]"
           style={{ width: `${progress}%`, transition: isPaused ? 'none' : 'width 100ms linear' }}
         />
      </div>

      {/* 3. Mobile Arrows & Indicators */}
      <div className="absolute bottom-8 left-0 right-0 lg:hidden flex justify-between items-center px-6 z-30">
         <div className="flex space-x-2">
            {HERO_SLIDES.map((_, index) => (
              <button
                key={index}
                onClick={() => goToSlide(index)}
                className={`h-1.5 rounded-full transition-all duration-300 ${
                  index === currentSlide ? 'w-8 bg-aucdt-gold' : 'w-2 bg-white/50'
                }`}
                aria-label={`Go to slide ${index + 1}`}
              />
            ))}
         </div>
         <div className="flex gap-4">
            <button 
                onClick={prevSlide} 
                className="p-3 bg-black/30 backdrop-blur-sm rounded-full text-white hover:bg-aucdt-gold hover:text-aucdt-maroon transition-colors border border-white/20 active:scale-95"
            >
               <ChevronLeft size={20} />
            </button>
            <button 
                onClick={nextSlide} 
                className="p-3 bg-black/30 backdrop-blur-sm rounded-full text-white hover:bg-aucdt-gold hover:text-aucdt-maroon transition-colors border border-white/20 active:scale-95"
            >
               <ChevronRight size={20} />
            </button>
         </div>
      </div>
    </section>
  );
};

export default HeroSlider;
